#include <bits/stdc++.h>
using namespace std;
int main(){
    int t;
    long long n,k;
    scanf("%d",&t);
    while(t--){
        scanf("%lld%lld",&n,&k);
        if(k==0)
            printf("1\n");
        else
            printf("%lld\n",((n/k-n%(n/k))-1)/2/k+1);
    }
    return 0;
}
